-- Astha Gas Agency — 45-day demo data (2026-05-27 → 2026-07-10)
-- Generated by prisma/seed-demo.mts. Uses the real employee / cylinder ids already in the DB.
-- Safe to re-import: clears the same window / loans / deductions first.
SET NAMES utf8mb4;
START TRANSACTION;
DELETE FROM `DailyDelivery` WHERE `date` >= '2026-05-27 00:00:00' AND `date` <= '2026-07-10 00:00:00';
DELETE FROM `LoanTransaction`;
DELETE FROM `MonthlyDeduction`;
COMMIT;
